// ═══ TOPOLOGY ═══
const Topology = ({onSelectDevice,selectedDeviceId,devices,setDevices,onConfigDevice}) => {
  const [links,setLinks] = useState([
    {id:"l1",from:"pc1",to:"sw1"},
    {id:"l2",from:"pc2",to:"sw1"},
    {id:"l3",from:"sw1",to:"rt1"},
  ]);
  const [dragging,setDragging] = useState(null);
  const [offset,setOffset] = useState({x:0,y:0});
  const [tool,setTool] = useState("select");
  const [linking,setLinking] = useState(null);
  const [termDevice,setTermDevice] = useState(null);
  const [selected,setSelected] = useState(null);
  const canvasRef = useRef(null);
  const counter = useRef(20);

  const getCenter = d=>({x:d.x+40,y:d.y+40});

  const handleMouseDown = (e,dev) => {
    e.stopPropagation();
    if(tool==="link"){
      if(!linking) setLinking(dev.id);
      else if(linking!==dev.id){
        const exists=links.find(l=>(l.from===linking&&l.to===dev.id)||(l.from===dev.id&&l.to===linking));
        if(!exists) setLinks(p=>[...p,{id:`l${Date.now()}`,from:linking,to:dev.id}]);
        setLinking(null);
      }
      return;
    }
    if(tool==="delete"){
      setDevices(p=>p.filter(d=>d.id!==dev.id));
      setLinks(p=>p.filter(l=>l.from!==dev.id&&l.to!==dev.id));
      if(selectedDeviceId===dev.id) onSelectDevice&&onSelectDevice(null);
      return;
    }
    setDragging(dev.id);
    setOffset({x:e.clientX-dev.x,y:e.clientY-dev.y});
    setSelected(dev.id);
    onSelectDevice&&onSelectDevice(dev);
  };

  const handleMouseMove = useCallback((e)=>{
    if(!dragging) return;
    const canvas=canvasRef.current?.getBoundingClientRect();
    if(!canvas) return;
    setDevices(p=>p.map(d=>d.id===dragging?{...d,x:Math.max(0,Math.min(e.clientX-offset.x,canvas.width-80)),y:Math.max(0,Math.min(e.clientY-offset.y,canvas.height-80))}:d));
  },[dragging,offset,setDevices]);

  const addDevice = (type,model) => {
    counter.current++;
    const info=DEVICE_TYPES[type];
    setDevices(p=>[...p,{id:`${type}${counter.current}`,type,name:`${info.label}${counter.current}`,model:model.name,x:180+Math.random()*240,y:140+Math.random()*180}]);
  };

  return (
    <div style={{flex:1,display:"flex",flexDirection:"column",background:"#f8fafc",overflow:"hidden"}}>
      <div style={{background:"#fff",borderBottom:"1px solid #e5e7eb",padding:"8px 16px",display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
        <span style={{fontSize:10,fontWeight:700,color:"#9ca3af",marginRight:4}}>ADD DEVICE:</span>
        {Object.entries(DEVICE_TYPES).map(([type,info])=>(
          <button key={type} onClick={()=>addDevice(type,info.models[0])}
            style={{background:`${info.color}12`,border:`1px solid ${info.color}40`,color:info.color,padding:"5px 10px",borderRadius:6,cursor:"pointer",fontSize:11,fontWeight:700,display:"flex",alignItems:"center",gap:5}}>
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{info.icon}</svg>
            {info.label}
          </button>
        ))}
        <div style={{width:1,background:"#e5e7eb",height:24,margin:"0 6px"}}/>
        <span style={{fontSize:10,fontWeight:700,color:"#9ca3af",marginRight:4}}>TOOL:</span>
        {[{id:"select",label:"Select"},{id:"link",label:"Link"},{id:"delete",label:"Delete"}].map(t=>(
          <button key={t.id} onClick={()=>{setTool(t.id);setLinking(null);}}
            style={{background:tool===t.id?"#1d4ed8":"#f3f4f6",border:"1px solid",borderColor:tool===t.id?"#1d4ed8":"#e5e7eb",color:tool===t.id?"#fff":"#374151",padding:"5px 12px",borderRadius:6,cursor:"pointer",fontSize:11,fontWeight:700}}>
            {t.label}
          </button>
        ))}
        {linking&&<div style={{background:"#fef3c7",border:"1px solid #fde68a",color:"#92400e",padding:"4px 12px",borderRadius:6,fontSize:11,fontWeight:600}}>Click device to link...</div>}
      </div>

      <div style={{flex:1,display:"flex",overflow:"hidden"}}>
        <div ref={canvasRef} style={{flex:1,position:"relative",background:"#f1f5f9",backgroundImage:"radial-gradient(#cbd5e1 1px, transparent 1px)",backgroundSize:"24px 24px",cursor:tool==="link"?"crosshair":tool==="delete"?"not-allowed":"default",overflow:"hidden"}}
          onMouseMove={handleMouseMove} onMouseUp={()=>setDragging(null)}
          onClick={()=>{if(tool==="select"){setSelected(null);onSelectDevice&&onSelectDevice(null);}}}>

          <svg style={{position:"absolute",inset:0,width:"100%",height:"100%",pointerEvents:"none"}}>
            {links.map(link=>{
              const from=devices.find(d=>d.id===link.from);
              const to=devices.find(d=>d.id===link.to);
              if(!from||!to) return null;
              const fc=getCenter(from);const tc=getCenter(to);
              const mx=(fc.x+tc.x)/2;const my=(fc.y+tc.y)/2;
              return (
                <g key={link.id}>
                  <line x1={fc.x} y1={fc.y} x2={tc.x} y2={tc.y} stroke="#94a3b8" strokeWidth="2" strokeDasharray="6,3"/>
                  <circle cx={mx} cy={my} r="8" fill="#fff" stroke="#e5e7eb" strokeWidth="1" style={{cursor:"pointer",pointerEvents:"all"}} onClick={()=>setLinks(p=>p.filter(l=>l.id!==link.id))}/>
                  <text x={mx} y={my+4} textAnchor="middle" fontSize="10" fill="#ef4444" style={{pointerEvents:"all",cursor:"pointer"}} onClick={()=>setLinks(p=>p.filter(l=>l.id!==link.id))}>x</text>
                </g>
              );
            })}
          </svg>

          {devices.map(dev=>{
            const info=DEVICE_TYPES[dev.type];
            const isSel=selected===dev.id||selectedDeviceId===dev.id;
            return (
              <div key={dev.id} style={{position:"absolute",left:dev.x,top:dev.y,width:80,userSelect:"none"}}
                onMouseDown={e=>handleMouseDown(e,dev)}
                onDoubleClick={()=>{if(tool==="select") onConfigDevice&&onConfigDevice(dev);}}>
                <div style={{width:80,height:80,background:info.bg,border:`2px solid ${isSel?info.color:"#e5e7eb"}`,borderRadius:12,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,boxShadow:isSel?`0 0 0 3px ${info.color}33`:"0 2px 8px #00000015",cursor:tool==="select"?"grab":"default",transition:"all 0.1s"}}>
                  <DevIcon type={dev.type} size={28}/>
                </div>
                <div style={{textAlign:"center",fontSize:10,fontWeight:700,color:"#374151",marginTop:4,whiteSpace:"nowrap"}}>{dev.name}</div>
                <div style={{textAlign:"center",fontSize:9,color:"#9ca3af",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",maxWidth:80}}>{dev.model}</div>
                {isSel&&tool==="select"&&(
                  <div style={{display:"flex",justifyContent:"center",gap:4,marginTop:4}}>
                    <button onClick={e=>{e.stopPropagation();onConfigDevice&&onConfigDevice(dev);}} style={{background:info.color,border:"none",color:"#fff",fontSize:9,padding:"2px 6px",borderRadius:4,cursor:"pointer",fontWeight:700}}>Config</button>
                    <button onClick={e=>{e.stopPropagation();setTermDevice(dev);}} style={{background:"#0f172a",border:"none",color:"#10b981",fontSize:9,padding:"2px 6px",borderRadius:4,cursor:"pointer",fontWeight:700,fontFamily:"monospace"}}>Term</button>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        <div style={{width:200,background:"#fff",borderLeft:"1px solid #e5e7eb",overflowY:"auto",padding:"10px"}}>
          <div style={{fontSize:10,color:"#9ca3af",textTransform:"uppercase",letterSpacing:1,marginBottom:10}}>Device Library</div>
          {Object.entries(DEVICE_TYPES).map(([type,info])=>(
            <div key={type} style={{marginBottom:14}}>
              <div style={{fontSize:10,fontWeight:700,color:info.color,marginBottom:6,display:"flex",alignItems:"center",gap:5}}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={info.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{info.icon}</svg>
                {info.label}
              </div>
              {info.models.map((model,i)=>(
                <button key={i} onClick={()=>addDevice(type,model)}
                  style={{width:"100%",background:"#f8fafc",border:"1px solid #e5e7eb",borderRadius:6,padding:"6px 8px",cursor:"pointer",textAlign:"left",marginBottom:3,transition:"all 0.1s"}}
                  onMouseEnter={e=>{e.currentTarget.style.background=`${info.color}10`;e.currentTarget.style.borderColor=info.color;}}
                  onMouseLeave={e=>{e.currentTarget.style.background="#f8fafc";e.currentTarget.style.borderColor="#e5e7eb";}}>
                  <div style={{fontSize:10,fontWeight:700,color:"#111827"}}>{model.name}</div>
                  <div style={{fontSize:9,color:"#9ca3af",marginTop:1}}>{model.ports}</div>
                </button>
              ))}
            </div>
          ))}
        </div>
      </div>

      {termDevice&&<DeviceTerminal device={termDevice} onClose={()=>setTermDevice(null)}/>}
    </div>
  );
};

// ═══ MAIN GUI ═══
export default function GUI({onCommand}) {
  const [selectedDevice,setSelectedDevice] = useState(null);
  const [modal,setModal] = useState(null);
  const [configDevice,setConfigDevice] = useState(null);
  const [saveStatus,setSaveStatus] = useState("");
  const [devices,setDevices] = useState([
    {id:"sw1",type:"switch",name:"Switch1",model:"Cisco 2960-24TT",x:300,y:200},
    {id:"rt1",type:"router",name:"Router1",model:"Cisco 2911",x:520,y:180},
    {id:"pc1",type:"pc",name:"PC1",model:"PC (Windows)",x:160,y:340},
    {id:"pc2",type:"pc",name:"PC2",model:"PC (Windows)",x:320,y:360},
  ]);

  const saveTopology = async () => {
    const fileName = prompt("Enter file name:", "MyTopology");
    if (!fileName) return;
    try {
      const res = await fetch("http://localhost:3001/api/topology", {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body: JSON.stringify({devices, fileName})
      });
      const data = await res.json();
      if(data.success){setSaveStatus("Saved!");setTimeout(()=>setSaveStatus(""),2000);}
    } catch(e){setSaveStatus("Error!");setTimeout(()=>setSaveStatus(""),2000);}
  };

  const loadTopology = async () => {
    try {
      const res = await fetch("http://localhost:3001/api/topology");
      const data = await res.json();
      if(data.devices) setDevices(data.devices);
    } catch(e){console.error("Load error:",e);}
  };

  React.useEffect(()=>{loadTopology();},[]);



  const handleRename = (id,newName) => {
    setDevices(p=>p.map(d=>d.id===id?{...d,name:newName}:d));
    setSelectedDevice(p=>p?.id===id?{...p,name:newName}:p);
    setConfigDevice(p=>p?.id===id?{...p,name:newName}:p);
  };

  const configCards = [
    {id:"ip",color:"#1d4ed8",title:"Set IP Address",desc:"Assign IP to interface",icon:<><rect x="2" y="3" width="20" height="14" rx="2"/><path d="M8 21h8M12 17v4"/></>},
    {id:"port",color:"#15803d",title:"Enable / Disable Port",desc:"Control port state",icon:<><path d="M18.36 6.64a9 9 0 1 1-12.73 0"/><line x1="12" y1="2" x2="12" y2="12"/></>},
    {id:"vlan",color:"#0e7490",title:"Configure VLAN",desc:"Create VLANs and assign ports",icon:<><polygon points="12 2 2 7 12 12 22 7 12 2"/><polyline points="2 17 12 22 22 17"/></>},
    {id:"hostname",color:"#7c3aed",title:"Change Hostname",desc:"Set device name",icon:<><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></>},
    {id:"save",color:"#92400e",title:"Save Configuration",desc:"Save settings to NVRAM",icon:<><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/></>},
    {id:"show",color:"#065f46",title:"Show Status",desc:"View interfaces and VLANs",icon:<><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></>},
    {id:"route",color:"#4f46e5",title:"Static Route",desc:"Add routing table entries",icon:<><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="18" x2="21" y2="18"/></>},
  ];

  return (
    <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
      <div style={{background:"#fff",borderBottom:"1px solid #e5e7eb",padding:"10px 16px"}}>
        <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginBottom:8}}>
  <button onClick={saveTopology} style={{background:"#15803d",border:"none",color:"#fff",padding:"6px 14px",borderRadius:6,cursor:"pointer",fontSize:11,fontWeight:700}}>
    {saveStatus || "Save Topology"}
  </button>
  <button onClick={loadTopology} style={{background:"#f3f4f6",border:"1px solid #e5e7eb",color:"#374151",padding:"6px 14px",borderRadius:6,cursor:"pointer",fontSize:11,fontWeight:700}}>
    Reload
  </button>
</div>
        <div style={{fontSize:11,color:selectedDevice?"#1d4ed8":"#9ca3af",marginBottom:8,fontWeight:700}}>
          {selectedDevice?`QUICK ACTIONS — ${selectedDevice.name} (${selectedDevice.model})`:"QUICK ACTIONS — Select a device in topology first"}
        </div>
        <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
          {configCards.map(card=>(
            <button key={card.id}
              onClick={()=>{if(selectedDevice) setModal(card); else alert("Please select a device in the topology first!");}}
              style={{background:selectedDevice?`${card.color}10`:"#f9fafb",border:`1px solid ${selectedDevice?card.color+"40":"#e5e7eb"}`,borderRadius:10,padding:"8px 12px",cursor:selectedDevice?"pointer":"not-allowed",display:"flex",alignItems:"center",gap:7,transition:"all 0.15s",opacity:selectedDevice?1:0.5}}
              onMouseEnter={e=>{if(selectedDevice){e.currentTarget.style.background=`${card.color}18`;e.currentTarget.style.borderColor=card.color;}}}
              onMouseLeave={e=>{if(selectedDevice){e.currentTarget.style.background=`${card.color}10`;e.currentTarget.style.borderColor=`${card.color}40`;}}}>
              <div style={{width:28,height:28,background:`${card.color}15`,borderRadius:7,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={card.color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">{card.icon}</svg>
              </div>
              <div style={{textAlign:"left"}}>
                <div style={{fontSize:11,fontWeight:700,color:"#111827"}}>{card.title}</div>
                <div style={{fontSize:9,color:"#9ca3af"}}>{card.desc}</div>
              </div>
            </button>
          ))}
        </div>
      </div>

      <Topology
        onSelectDevice={setSelectedDevice}
        selectedDeviceId={selectedDevice?.id}
        devices={devices}
        setDevices={setDevices}
        onConfigDevice={setConfigDevice}
      />

      {modal&&selectedDevice&&(
        <ActionModal action={modal} device={selectedDevice} onClose={()=>setModal(null)} onRename={handleRename}/>
      )}

      {configDevice&&(
        <ConfigPanel device={configDevice} onClose={()=>setConfigDevice(null)} onRename={handleRename}/>
      )}
    </div>
  );
}
